on:"\u{1F3C6} Champion!",done:"\u{1F389} Game over!",partyScore:"GAME SCORE",played:"Questions played:",bestStreakLbl:"Best streak:",saved:"Your progress is saved \u2014 retry level {n}!",retry:"Retry level {n} \u{1F504}",replay:"Play again \u{1F504}",seeBoard:"\u{1F3C6} See leaderboard",boardTitle:"\u{1F3C6} Leaderboard",boardEmpty:"No players yet \u2014 be the first! \u{1F947}",boardSort:"Ranked by best level reached, then total score.",loading:"Loading...",j5050:"50/50",jskip:"Skip",jheal:"+1 life",language:"LANGUAGE",country:"COUNTRY",countryPh:"E.g.: Nigeria, Kenya, USA...",countryHint:"1-2 questions about your country, the rest about the world \u{1F30D}",save:"Save \u2714",badgesTitle:"\u{1F396}\uFE0F My badges",badgesHint:"{a}/{b} unlocked \u2014 keep playing to collect them all!",newBadge:"\u{1F389} New badge unlocked!",whyLbl:"\u{1F4A1} ",settingsTitle:"\u2699\uFE0F Settings",statsSec:"MY STATISTICS",statGames:"Games",statCorrect:"Correct answers",statAccuracy:"Accuracy",profileSec:"PROFILE",editProfile:"\u{1F464} Edit my name and avatar",gameSec:"GAME",qCountLbl:"Questions per free game",timerLbl:"Timer per question",timerAuto:"Auto",timerOff:"None",themeSec:"THEME",soundLbl:"\u{1F50A} Sounds",vibLbl:"\u{1F4F3} Vibrations",dangerSec:"DANGER ZONE",reset:"\u{1F5D1}\uFE0F Reset my progress",resetConfirm:"Everything will be erased (level, score, badges). Confirm?",resetYes:"Yes, erase everything",cancel:"Cancel",version:"De l'Ignorance \xE0 la Lumi\xE8re \xB7 version {n}",savedToast:"\u2705 Saved",appTagline:"Every question is a step toward knowledge.",missionBtn:"\u{1F3AF} Our mission",missionTitle:"\u{1F3AF} Our mission",missionText:"De l'Ignorance \xE0 la Lumi\xE8re exists for one reason: to help everyone learn, grow, and build their knowledge, one day at a time. We believe curiosity is the first step toward the light \u2014 and that interactive, playful quizzes tailored to each person are one of the simplest, most joyful ways to get there. Whether you play for five minutes between tasks or aim for the top of the global leaderboard, our goal stays the same: turning every question into a small victory over ignorance.",reportBtn:"\u{1F6A9} Report an error",reportSent:"\u2705 Thanks, report sent!",suggestBtn:"\u{1F4A1} Suggest a question",suggestTitle:"\u{1F4A1} Suggest a question",suggestIntro:"A general-knowledge question you'd like to see in the game? Suggest it here!",suggestQPh:"Your question...",suggestAPh:"The correct answer (optional)",suggestSend:"Send suggestion",suggestSent:"\u2705 Thanks for your suggestion!",whatsNewTitle:"\u2728 What's new",whatsNewBtn:"Continue",whatsNew:["\u2601\uFE0F Connected to a real online account: your progress, profile and the global leaderboard now sync","The game keeps working normally even without a connection"],infoBtn:"\u2753 Help & Info",infoHubTitle:"\u2753 Help & Info",howToPlayBtn:"\u{1F4D6} How to play",helpBtn:"\u{1F4AC} Help (FAQ)",aboutBtn:"\u2139\uFE0F About",shareBtn:"\u{1F4E4} Share the game",shareMessage:"Come test your knowledge on De l'Ignorance \xE0 la Lumi\xE8re! An unlimited general-knowledge quiz, powered by AI \u{1F9E0}\u{1F3AE}",shareCopied:"Copied! Paste it to share with friends \u{1F389}",howToPlayTitle:"\u{1F4D6} How to play",helpTitle:"\u{1F4AC} Frequently asked questions",aboutTitle:"\u2139\uFE0F About",aboutDevBy:"Developed with passion by",aboutDevName:"\u{1F468}\u200D\u{1F4BB} Hdattaher Almansour",aboutDevLocation:"\u{1F4CD} Son of Abalak, Niger \u{1F1F3}\u{1F1EA}",aboutThanks:"Thank you to every player who uses De l'Ignorance \xE0 la Lumi\xE8re. This app was built to make learning fun, accessible, and engaging through thousands of general-knowledge questions.",aboutCopyright:"\xA9 2026 Hdattaher Almansour. All rights reserved.",aboutFooter:"Made by Hdattaher Almansour, son of Abalak (Niger).",privacyBtn:"\u{1F512} Privacy Policy",termsBtn:"\u{1F4DC} Terms of Use",contactBtn:"\u2709\uFE0F Contact us",rateBtn:"\u2B50 Rate the app",privacyTitle:"\u{1F512} Privacy Policy",privacyIntro:"Your privacy matters. Here's, simply, what De l'Ignorance \xE0 la Lumi\xE8re does and doesn't do with your data.",privacyPoints:["No ads, ever. De l'Ignorance \xE0 la Lumi\xE8re never sells or shares data with advertisers.","Your name, avatar, language and country are stored only to run the game (progress saving, leaderboard).","The global leaderboard is public: name, avatar, country, best level and score are visible to other players.","No sensitive information (email, phone, precise location, payment details) is ever requested.","You can reset and erase your progress anytime from Settings \u2192 Danger zone."],termsTitle:"\u{1F4DC} Terms of Use",termsPoints:["By using De l'Ignorance \xE0 la Lumi\xE8re, you agree to play fair, without cheating on the leaderboard.","Questions are generated automatically by an AI and may, rarely, contain inaccuracies.",'The app is provided "as is", with no absolute guarantee of the accuracy of its content.',`The "De l'Ignorance \xE0 la Lumi\xE8re" name, code and content may not be reproduced or redistributed without permission.`,"These terms may evolve with future app updates."],contactTitle:"\u2709\uFE0F Contact us",contactIntro:"A question, a suggestion, or a bug to report? Write to us, we're happy to answer.",contactEmail:"contact@quizgenie.app",contactCopied:"Copied! Paste it into your mail app \u{1F4E7}",rateTitle:"\u2B50 Rate the app",rateIntro:"Your feedback matters a lot for what's next for De l'Ignorance \xE0 la Lumi\xE8re!",rateThanks:"\u{1F64F} Thank you so much for your rating!",rules:[{icon:"\u{1F5FA}\uFE0F",title:"Adventure mode",text:"Progress through unlimited levels. Each level has 5 questions with rising difficulty."},{icon:"\u2764\uFE0F",title:"3 lives",text:"A wrong answer or running out of time costs a life. At 0 lives, the level restarts."},{icon:"\u26A1",title:"Speed bonus",text:"The faster you answer, the more points you earn! Harder questions are worth more too."},{icon:"\u{1F0CF}",title:"Jokers",text:"50/50, Skip and +1 life: one of each per game, use them at the right moment."},{icon:"\u{1F3B2}",title:"Free play",text:"Pick your category and difficulty freely, with no adventure-mode pressure."},{icon:"\u{1F396}\uFE0F",title:"Badges",text:"Unlock 8 badges by progressing, chaining correct answers, or finishing a level without losing a life."},{icon:"\u{1F3C6}",title:"Global leaderboard",text:"Your best level and total score are shared with players around the world."}],faq:[{q:"The game isn't asking questions in my language?",a:"Check your language under Settings \u2192 Language. New questions will follow that choice."},{q:'What does "Offline mode" mean?',a:"If the AI can't respond (connection lost), the game uses a small local question bank (in French) so you can keep playing."},{q:"How do I change my name or avatar?",a:"Go to Settings \u2192 Profile \u2192 Edit my name and avatar."},{q:"I want to start over, how do I do that?",a:"In Settings \u2192 Danger zone, you can reset all your progress."},{q:"How does the leaderboard work?",a:"It's ranked by best level reached, then total score, and includes every player with a profile."}],playerLevelLbl:"Player level",xpLbl:"XP",coinsLbl:"Coins",playerLevelUp:"\u{1F389} Player level {n}!",chestEarned:"\u{1F381} Chest earned!",openChest:"Open chest",chestOpening:"Opening chest...",chestReward:"You earned:",chestContinue:"Great!",chestTier:{bronze:"Bronze Chest",silver:"Silver Chest",gold:"Gold Chest",diamond:"Diamond Chest",legendary:"Legendary Chest"},dailyStreakTitle:"\u{1F525} Daily streak",dailyStreakDesc:"Day {n} in a row!",dailyStreakMilestone:"\u{1F389} {n}-day milestone reached \u2014 special reward!",dailyStreakClaim:"Claim",dailyStreakLost:"\u{1F622} Your daily streak was broken. Play every day to build it back up!",profileBtn:"\u{1F464} My profile",profileTitle:"\u{1F464} My profile",profilePlaytime:"Time played",profileJoinDate:"Member since",profileBadgesCount:"Badges",profileBestSt